import React, { useState, useEffect } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { clearAuth } from '../api';
import { 
  Menu, X, Home, MessageSquare, 
  AlertTriangle, Bell, Users, LogOut, ChevronRight 
} from 'lucide-react';

const navItems = [
  { name: 'Home',      path: '/user/home',      icon: Home },
  { name: 'Feedback',  path: '/user/feedback',  icon: MessageSquare },
  { name: 'Complaint', path: '/user/complaint', icon: AlertTriangle },
  { name: 'Notices',   path: '/user/notices',   icon: Bell },
  { name: 'Societies', path: '/user/societies', icon: Users },
];

const Navbar = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const [menuOpen, setMenuOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);

  // Scroll effect for navbar glassmorphism
  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const handleLogout = () => {
    clearAuth();
    navigate('/login');
  };

  return (
    <nav className={`fixed top-0 left-0 right-0 z-[1000] transition-all duration-300 ${
      scrolled ? 'py-2 px-4' : 'py-4 px-6'
    }`}>
      <div className={`mx-auto max-w-7xl transition-all duration-300 rounded-2xl border border-white/10 ${
        scrolled ? 'bg-slate-950/80 backdrop-blur-xl shadow-2xl' : 'bg-slate-900/40 backdrop-blur-md'
      }`}>
        <div className="flex h-16 items-center justify-between px-6">

          {/* Logo with Animation */}
          <motion.div 
            whileHover={{ scale: 1.05 }}
            whileTap={{ scale: 0.95 }}
            className="flex cursor-pointer items-center gap-3" 
            onClick={() => navigate('/user/home')}
          >
            <div className="relative flex h-10 w-10 items-center justify-center rounded-lg bg-gradient-to-br from-amber-400 to-orange-600 shadow-lg shadow-orange-500/20">
              <span className="text-xl font-bold text-white">HM</span>
              <div className="absolute inset-0 rounded-lg bg-white/20 animate-pulse"></div>
            </div>
            <span className="hidden sm:block text-xl font-black tracking-tighter text-transparent bg-clip-text bg-gradient-to-r from-white to-slate-400">
              HOSTELMATE
            </span>
          </motion.div>

          {/* Desktop Nav Items */}
          <div className="hidden lg:flex items-center gap-1 bg-white/5 p-1 rounded-xl border border-white/5">
            {navItems.map(({ name, path, icon: Icon }) => {
              const isActive = location.pathname === path;
              return (
                <Link key={path} to={path} className="relative group">
                  <div className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-semibold transition-all duration-300 ${
                    isActive ? 'text-amber-400' : 'text-slate-400 hover:text-white'
                  }`}>
                    <Icon size={18} className={isActive ? 'animate-bounce' : ''} />
                    <span>{name}</span>
                    {isActive && (
                      <motion.div 
                        layoutId="nav-glow"
                        className="absolute inset-0 bg-amber-400/10 rounded-lg border border-amber-400/20"
                      />
                    )}
                  </div>
                </Link>
              );
            })}
          </div>

          {/* Action Buttons */}
          <div className="flex items-center gap-3">
            <button 
              onClick={handleLogout}
              className="hidden md:flex items-center gap-2 rounded-xl bg-red-500/10 px-5 py-2.5 text-sm font-bold text-red-500 border border-red-500/20 transition-all hover:bg-red-500 hover:text-white hover:shadow-[0_0_15px_rgba(239,68,68,0.4)]"
            >
              <LogOut size={16} />
              Logout
            </button>

            {/* Mobile Toggle */}
            <motion.button
              whileTap={{ scale: 0.9 }}
              onClick={() => setMenuOpen(!menuOpen)}
              className="lg:hidden flex h-10 w-10 items-center justify-center rounded-xl bg-white/5 text-amber-500 hover:bg-white/10"
            >
              {menuOpen ? <X size={24} /> : <Menu size={24} />}
            </motion.button>
          </div>
        </div>
      </div>

      {/* Animated Mobile Menu */}
      <AnimatePresence>
        {menuOpen && (
          <motion.div
            initial={{ opacity: 0, y: -20, scale: 0.95 }}
            animate={{ opacity: 1, y: 10, scale: 1 }}
            exit={{ opacity: 0, y: -20, scale: 0.95 }}
            className="lg:hidden mx-auto max-w-[95%] mt-2 overflow-hidden rounded-3xl border border-white/10 bg-slate-950/95 backdrop-blur-2xl shadow-2xl"
          >
            <div className="p-4 space-y-2">
              {navItems.map(({ name, path, icon: Icon }) => (
                <motion.div key={path} whileTap={{ x: 10 }}>
                  <Link
                    to={path}
                    onClick={() => setMenuOpen(false)}
                    className={`flex items-center justify-between rounded-2xl px-5 py-4 transition-all ${
                      location.pathname === path 
                        ? 'bg-amber-500/20 text-amber-400 ring-1 ring-amber-500/30' 
                        : 'text-slate-400 hover:bg-white/5'
                    }`}
                  >
                    <div className="flex items-center gap-4 text-base font-bold">
                      <Icon size={22} />
                      {name}
                    </div>
                    <ChevronRight size={18} className="opacity-50" />
                  </Link>
                </motion.div>
              ))}

              <div className="mt-4 pt-4 border-t border-white/10">
                <button
                  onClick={handleLogout}
                  className="flex w-full items-center justify-center gap-3 rounded-2xl bg-red-500 px-5 py-4 text-base font-black text-white shadow-lg shadow-red-500/20 transition-active"
                >
                  <LogOut size={20} />
                  SIGN OUT
                </button>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </nav>
  );
};

export default Navbar;
